export enum Realm {
    Mortal = '凡人',
    QiRefinement = '练气',
    FoundationEstablishment = '筑基',
    Zifu = '紫府',
    JinDan = '金丹',
    YuanYing = '元婴',
    YuanShen = '化神'
}

export enum Element {
    Gold = '金',
    Wood = '木',
    Water = '水',
    Fire = '火',
    Earth = '土'
}

export type TaskType = 'Cultivation' | 'Exploration' | 'Research' | 'Patrol' | 'Idle' | 'Mission' | 'Alchemy' | 'Smithing' | 'Travel' | 'None';
export type TalentTier = '凡人' | '平庸' | '普通' | '超凡' | '天才' | '绝世' | '绝世天骄';
export type RootGrade = '凡人' | '伪灵根' | '下品灵根' | '中品灵根' | '上品灵根' | '极品灵根';
export type DevelopmentPlan = 'Combat' | 'Alchemy' | 'Smithing' | 'Talisman' | 'Balanced';
export type MethodQuality = '上等' | '中等' | '下等';
export type MethodType = 'Cultivation' | 'Combat' | 'Movement';

export type BuildingCategory = '资源产出' | '家族功能' | '修行基础';

export interface Building {
    id: string;
    type: string;
    level: number;
    assignedMemberId: string | null;
    isFinished: boolean;
    turnsRemaining: number;
    activeProduction?: {
        recipeId: number;
        turnsRemaining: number;
        type: 'Alchemy' | 'Smithing';
    };
}

export interface Inventory {
    herbs: Record<number, number>;
    minerals: Record<number, number>;
    paper: number;
    pills: Record<number, number>;
    weapons: Record<number, number>;
    methods: Record<number, number>;
    scrolls: Record<number, number>;
}

export interface MethodBuffs {
    cultivationSpeed?: number;
    attack?: number;
    defense?: number;
    divineSense?: number;
    maxAge?: number;
}

export interface MethodRequirements {
    realm?: Realm;
    minRoots?: Partial<ElementalRoots>;
    minRootGrade?: RootGrade;
}

export interface CultivationMethod {
    id: number;
    name: string;
    grade: number;
    quality: MethodQuality;
    type: MethodType;
    element: Element | '无';
    desc: string;
    bonus: string;
    buffs: MethodBuffs;
    requirements: MethodRequirements;
}

export interface ElementalRoots {
    gold: number;
    wood: number;
    water: number;
    fire: number;
    earth: number;
}

export interface SpecializedTalents {
    战斗天赋: {
        剑法: number;
        拳法: number;
        枪法: number;
        刀法: number;
        弓箭: number;
    };
    百艺天赋: {
        炼丹: number;
        炼器: number;
        制符: number;
        阵法: number;
    };
}

export interface ClanMember {
    id: string;
    name: string;
    title?: string; 
    gender: '男' | '女';
    generation: number; 
    realm: Realm;
    subRealm: number; 
    age: number;
    maxAge: number;
    physique: string;
    aptitude: number;
    comprehension: number;
    divineSense: number;
    roots: ElementalRoots;
    rootGrade: RootGrade;
    talents: SpecializedTalents;
    proficiencies: Record<keyof SpecializedTalents['百艺天赋'], number>;
    combatProficiencies: Record<keyof SpecializedTalents['战斗天赋'], number>;
    tier: TalentTier;

    element: Element;
    status: 'healthy' | 'injured' | 'dead';
    loyalty: number; 
    assignment: TaskType;
    legacyPoints: number; 
    deathYear?: number;

    mainMethodId: number | null;
    movementMethodId: number | null;
    auxMethodIds: number[];

    equippedItems: {
        weapon: number | null;
        armor: number | null;
        accessory: number | null;
        treasure: number | null;
    };
    personalInventory: Inventory;

    cultivationProgress: number;
    developmentPlan: DevelopmentPlan;
    divineAbilities: string[];
    sect: string;
    position: string;

    // Relationships
    fatherId?: string | null;
    motherId?: string | null;
    spouseId?: string | null;
    mentorId?: string | null;
}

export type RegionCategory = 'Natural' | 'Stakeholder' | 'Mystic' | 'Resource';
export type RegionType = 'lake' | 'mountain' | 'forest' | 'city' | 'sect' | 'ruins' | 'cave' | 'island' | 'desert' | 'mine' | 'field';

export type FactionType = '望月李氏' | '北寒宗' | '天一剑宗' | '邵家' | '魏家' | '离火门' | '南海散修' | '无';

export interface Region {
    id: string;
    name: string;
    description: string;
    difficulty: number;
    owner: FactionType;
    x: number;
    y: number;
    type: RegionType;
    category: RegionCategory;
    isDiscovered: boolean;
    resources: string[];

    // 领土控制逻辑
    controlValue: number; // 0-100, 李家控制力
    occupancyStatus: 'idle' | 'contested' | 'secured'; 

    // 产出配置
    production?: {
        stones?: number;
        merit?: number;
        items?: Record<number, number>;
    };

    activeMission?: {
        memberId: string;
        turnsRemaining: number;
        totalTurns: number;
        type: 'Occupy' | 'Explore' | 'War' | 'Mystic';
    };

    // 临时点位标记
    isTemporary?: boolean;
    expiryYear?: number;
}

export interface GameState {
    year: number;
    season: number; // 1:春, 2:夏, 3:秋, 4:冬
    spiritStones: number;
    merit: number; 
    luck: number; 
    members: ClanMember[];
    regions: Region[];
    buildings: Building[];
    inventory: Inventory;
    currentRegionId: string;
    isMirrorActive: boolean;
    logs: string[];
    heritagePool: number;
    unlockedPositions: string[];
}

import { TaskType, DevelopmentPlan } from '../types';

export const TASK_INFO_DATA = {
    Cultivation: { label: '闭关修炼', color: 'text-blue-400', desc: '修士默认状态，一心问道，进益最快。' },
    Research: { label: '研习典籍', color: 'text-purple-400', desc: '担任长老或执事，负责整理家族经略。' },
    Alchemy: { label: '炼制丹药', color: 'text-pink-400', desc: '担任炼丹师，为族人开炉炼药。' },
    Smithing: { label: '炼制法器', color: 'text-cyan-400', desc: '担任炼器师，打造家族神兵。' },
    Idle: { label: '休养生息', color: 'text-emerald-400', desc: '因伤退居二线，调理气息。' },
    Mission: { label: '外出派遣', color: 'text-orange-400', desc: '正为家族奔波劳碌，或占领地，或探秘境。' },
    Travel: { label: '外出游历', color: 'text-yellow-500', desc: '游历天罡大陆，寻求机缘造化。' },
    None: { label: '无', color: 'text-gray-500', desc: '凡人之躯，不入仙途。' },
    // 兼容旧数据的备用项
    Exploration: { label: '游历中', color: 'text-yellow-500', desc: '游历天罡大陆。' },
    Patrol: { label: '镇守中', color: 'text-red-400', desc: '守护家族领地。' }
};

export const DEVELOPMENT_PLANS_DATA: Record<DevelopmentPlan, { label: string; desc: string }> = {
    Combat: { label: '战修之道', desc: '侧重斗法。' },
    Alchemy: { label: '丹鼎之道', desc: '侧重炼丹。' },
    Smithing: { label: '百器之道', desc: '侧重炼器。' },
    Talisman: { label: '符箓之道', desc: '侧重画符。' },
    Balanced: { label: '中庸平衡', desc: '平稳增长。' }
};

import React, { useState } from 'react';
import { GameState, ClanMember, Region, Realm, Building, Inventory, TaskType } from './types';
import { INITIAL_MEMBERS, INITIAL_REGIONS, REALM_ORDER, BUILDING_TYPES, ALL_ITEM_DETAILS } from './constants';
import { CLAN_MASTER_REGISTRY } from './data/master_registry';
import ClanDashboard from './components/ClanDashboard';
import WorldMap from './components/WorldMap';
import ClanManagement from './components/ClanManagement';
import BreakthroughModal from './components/BreakthroughModal';
import { generateYearlyEvent } from './services/geminiService';
import { calculateQuarterlyExpGain, getRequiredExp } from './components/CultivationSystem';

const SEASON_NAMES = ['', '春', '夏', '秋', '冬'];

const App: React.FC = () => {
    const [state, setState] = useState<GameState>({
        year: 1,
        season: 1,
        spiritStones: CLAN_MASTER_REGISTRY.spiritStones,
        merit: CLAN_MASTER_REGISTRY.merit,
        luck: CLAN_MASTER_REGISTRY.luck,
        members: INITIAL_MEMBERS,
        regions: INITIAL_REGIONS,
        buildings: [],
        inventory: CLAN_MASTER_REGISTRY.inventory,
        currentRegionId: '',
        isMirrorActive: false,
        logs: ["太平历初，望月李氏在此立基。昊天镜悬于祠堂，照破虚妄。"],
        heritagePool: CLAN_MASTER_REGISTRY.heritagePool,
        unlockedPositions: ['家主', '弟子'],
    });

    const [event, setEvent] = useState<any>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isDashboardVisible, setIsDashboardVisible] = useState(true);
    const [isManagementVisible, setIsManagementVisible] = useState(false);
    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);

    // Breakthrough State
    const [breakingMemberId, setBreakingMemberId] = useState<string | null>(null);

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => {
            let yearLogs: string[] = [];
            let updatedMembers = [...prev.members];

            updatedMembers = updatedMembers.map(m => {
                if (m.id !== id) return m;

                let nm = { ...m, ...updates };

                if (updates.cultivationProgress !== undefined && nm.realm !== Realm.Mortal) {
                    let progress = nm.cultivationProgress;
                    let subRealm = nm.subRealm;
                    const realmIdx = REALM_ORDER.indexOf(nm.realm);

                    let currentReq = getRequiredExp(realmIdx, subRealm);
                    while (progress >= currentReq && subRealm < 9) {
                        progress -= currentReq;
                        subRealm += 1;
                        currentReq = getRequiredExp(realmIdx, subRealm);
                        yearLogs.push(`【${prev.year}载·晋升】${nm.name} 气息升华，实时突破至 ${nm.realm} ${subRealm}层。`);
                    }

                    if (subRealm === 9 && progress >= currentReq) {
                        progress = currentReq; 
                        if (m.subRealm < 9 || m.cultivationProgress < currentReq) {
                            yearLogs.push(`【${prev.year}载·瓶颈】${nm.name} 触碰天门，已达 ${nm.realm} 巅峰之境。`);
                        }
                    }

                    nm.cultivationProgress = progress;
                    nm.subRealm = subRealm;
                }

                return nm;
            });

            if (updates.position === '家主') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '家主' && m.id !== id) ? { ...m, position: '弟子' } : m
                );
            }

            return {
                ...prev,
                members: updatedMembers,
                logs: yearLogs.length > 0 ? [...yearLogs, ...prev.logs].slice(0, 30) : prev.logs
            };
        });
    };

    const handleUnlockPosition = (posName: string, cost: number) => {
        if (state.merit < cost) return;
        setState(prev => ({
            ...prev,
            merit: prev.merit - cost,
            unlockedPositions: [...prev.unlockedPositions, posName],
            logs: [`【${prev.year}载·职位】册封权限已开启：${posName}。`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleUpdateBuilding = (id: string, updates: Partial<Building>) => {
        setState(prev => ({
            ...prev,
            buildings: prev.buildings.map(b => b.id === id ? { ...b, ...updates } : b)
        }));
    };

    const handleAddBuilding = (type: string) => {
        const info = BUILDING_TYPES[type];
        if (state.spiritStones < info.baseCost) return;

        const newBuilding: Building = {
            id: `b_${Date.now()}`,
            type,
            level: 1,
            assignedMemberId: null,
            isFinished: false,
            turnsRemaining: info.baseTurns
        };

        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones - info.baseCost,
            buildings: [...prev.buildings, newBuilding],
            logs: [`【${prev.year}载·营建】家族开始营造 ${info.name}。`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleAssignBuilding = (buildingId: string, memberId: string | null) => {
        setState(prev => ({
            ...prev,
            buildings: prev.buildings.map(b => {
                if (b.id === buildingId) {
                    return { ...b, assignedMemberId: memberId };
                }
                if (memberId !== null && b.assignedMemberId === memberId) {
                    return { ...b, assignedMemberId: null };
                }
                return b;
            })
        }));
    };

    // 计算状态
    const getMemberStatus = (member: ClanMember, buildings: Building[]): TaskType => {
        if (member.realm === Realm.Mortal) return 'None';
        if (member.status === 'injured') return 'Idle'; // 休养生息

        // 检查是否正在执行领土任务
        const isOnMission = state.regions.some(r => r.activeMission?.memberId === member.id);
        if (isOnMission) return 'Mission';

        // 检查正在游历 (如果当前状态已标记为Travel)
        if (member.assignment === 'Travel') return 'Travel';

        // 检查建筑指派
        const alchemyRoom = buildings.find(b => b.type === 'AlchemyRoom' && b.assignedMemberId === member.id);
        if (alchemyRoom) return 'Alchemy';

        const smithy = buildings.find(b => b.type === 'Smithy' && b.assignedMemberId === member.id);
        if (smithy) return 'Smithing';

        // 检查职位指派：长老、执事自动开启研习典籍
        if (member.position === '长老' || member.position === '执事') return 'Research';

        return 'Cultivation';
    };

    const handleNextTurn = async () => {
        setIsProcessing(true);
        let turnLogs: string[] = [];
        let stoneGain = 50; 
        let meritGain = 2;
        let bonusInventory: Inventory = { herbs: {}, minerals: {}, paper: 0, pills: {}, weapons: {}, methods: {}, scrolls: {} };

        const currentYear = state.year;
        const currentSeason = state.season;
        const nextSeason = currentSeason >= 4 ? 1 : currentSeason + 1;
        const isYearIncrement = currentSeason === 4;

        const updatedBuildings = state.buildings.map(b => {
            let nb = { ...b };
            if (!nb.isFinished) {
                const remaining = nb.turnsRemaining - 1;
                if (remaining <= 0) {
                    turnLogs.push(`【${currentYear}载·${SEASON_NAMES[currentSeason]}】${BUILDING_TYPES[nb.type].name} 顺利落成。`);
                    nb = { ...nb, isFinished: true, turnsRemaining: 0 };
                } else {
                    nb = { ...nb, turnsRemaining: remaining };
                }
            } else {
                if (nb.activeProduction) {
                    const rem = nb.activeProduction.turnsRemaining - 1;
                    if (rem <= 0) {
                        const { recipeId, type } = nb.activeProduction;
                        const recipeName = ALL_ITEM_DETAILS[recipeId]?.name || '未知产物';
                        turnLogs.push(`【${currentYear}载·${SEASON_NAMES[currentSeason]}】${BUILDING_TYPES[nb.type].name} 完成了 ${recipeName} 的制作。`);

                        if (type === 'Alchemy') {
                            bonusInventory.pills[recipeId] = (bonusInventory.pills[recipeId] || 0) + 1;
                        } else {
                            bonusInventory.weapons[recipeId] = (bonusInventory.weapons[recipeId] || 0) + 1;
                        }

                        nb.activeProduction = undefined;
                    } else {
                        nb.activeProduction = { ...nb.activeProduction, turnsRemaining: rem };
                    }
                }
            }

            if (nb.isFinished) {
                if (nb.type === 'Market' && nb.assignedMemberId) stoneGain += 200;
                if (nb.type === 'SpiritField') {
                    bonusInventory.herbs[1300] = (bonusInventory.herbs[1300] || 0) + 5;
                }
            }
            return nb;
        });

        const memberStatusChanges: Record<string, Partial<ClanMember>> = {};

        const updatedRegions = state.regions.map(r => {
            let nr = { ...r };

            if (nr.owner === '望月李氏' && nr.production) {
                if (nr.production.stones) stoneGain += nr.production.stones;
                if (nr.production.merit) meritGain += nr.production.merit;
                if (nr.production.items) {
                    Object.entries(nr.production.items).forEach(([idStr, count]) => {
                        const id = parseInt(idStr);
                        if (nr.type === 'field') bonusInventory.herbs[id] = (bonusInventory.herbs[id] || 0) + count;
                        else if (nr.type === 'mine') bonusInventory.minerals[id] = (bonusInventory.minerals[id] || 0) + count;
                    });
                }
            }

            if (nr.activeMission) {
                const rem = nr.activeMission.turnsRemaining - 1;
                if (rem <= 0) {
                    const member = state.members.find(m => m.id === nr.activeMission!.memberId);
                    if (member) {
                        const mType = nr.activeMission.type;
                        const memberPower = REALM_ORDER.indexOf(member.realm) * 10 + member.subRealm;
                        const diff = nr.difficulty;

                        let riskSuccess = true;
                        if (memberPower < diff) {
                            const riskFactor = (diff - memberPower) / 10; 
                            const roll = Math.random();
                            if (roll < riskFactor * 0.2) {
                                memberStatusChanges[member.id] = { status: 'dead', deathYear: currentYear };
                                turnLogs.push(`【${currentYear}载·讣闻】${member.name} 在 ${nr.name} 不幸陨落。`);
                                riskSuccess = false;
                            } else if (roll < riskFactor * 0.8) {
                                memberStatusChanges[member.id] = { status: 'injured' };
                                turnLogs.push(`【${currentYear}载·伤情】${member.name} 在 ${nr.name} 受了重伤。`);
                                riskSuccess = false;
                            }
                        }

                        if (riskSuccess) {
                            if (mType === 'Occupy' || mType === 'War') {
                                nr.owner = '望月李氏';
                                turnLogs.push(`【${currentYear}载·版图】${member.name} 平定了 ${nr.name}。`);
                            } else {
                                const rewardPool = nr.resources;
                                const rewardName = rewardPool[Math.floor(Math.random() * rewardPool.length)];
                                turnLogs.push(`【${currentYear}载·探查】${member.name} 在 ${nr.name} 寻得 ${rewardName}。`);
                                const foundItem = Object.values(ALL_ITEM_DETAILS).find(item => item.name === rewardName);
                                if (foundItem) {
                                    bonusInventory.minerals[foundItem.id] = (bonusInventory.minerals[foundItem.id] || 0) + 1;
                                }
                            }
                        }
                    }
                    nr.activeMission = undefined;
                } else {
                    nr.activeMission = { ...nr.activeMission, turnsRemaining: rem };
                }
            }
            return nr;
        });

        const updatedMembers = state.members.map(m => {
            let nm = { ...m, ...(memberStatusChanges[m.id] || {}) };
            if (nm.status === 'dead') return nm;

            // 确定本轮状态
            nm.assignment = getMemberStatus(nm, updatedBuildings);

            if (isYearIncrement) {
                nm.age += 1;
                if (nm.age >= nm.maxAge) {
                    nm.status = 'dead'; nm.deathYear = currentYear;
                    turnLogs.push(`【${currentYear}载·春】${nm.name} 寿元耗尽，溘然长逝。`);
                }
            }

            const hasRoots = (Object.values(nm.roots) as number[]).some(v => v > 0);

            if (hasRoots && nm.realm !== Realm.Mortal && nm.status === 'healthy') {
                const baseGain = calculateQuarterlyExpGain(nm);
                let multiplier = 1.0; 

                // 根据要求设定的经验倍率
                switch(nm.assignment) {
                    case 'Cultivation': multiplier = 1.0; break; // 闭关：100%
                    case 'Idle': multiplier = 0.2; break; // 休养生息：20%
                    case 'Research':
                    case 'Alchemy':
                    case 'Smithing': multiplier = 0.6; break; // 职司：60%
                    case 'Mission': multiplier = 0.4; break; // 外出派遣：40%
                    case 'Travel': multiplier = 0.1; break; // 外出游历：10%
                    default: multiplier = 1.0;
                }

                const finalGain = baseGain * multiplier;
                let newProgress = nm.cultivationProgress + finalGain;
                let finalSubRealm = nm.subRealm;
                const realmIdx = REALM_ORDER.indexOf(nm.realm);

                let currentReq = getRequiredExp(realmIdx, finalSubRealm);
                while (newProgress >= currentReq && finalSubRealm < 9) {
                    newProgress -= currentReq;
                    finalSubRealm += 1;
                    currentReq = getRequiredExp(realmIdx, finalSubRealm);
                    turnLogs.push(`【${currentYear}载·${SEASON_NAMES[currentSeason]}】${nm.name} 晋升至 ${nm.realm} ${finalSubRealm}层。`);
                }

                if (finalSubRealm === 9 && newProgress >= currentReq) {
                    newProgress = currentReq;
                    if (nm.subRealm < 9 || nm.cultivationProgress < currentReq) {
                        turnLogs.push(`【${currentYear}载·${SEASON_NAMES[currentSeason]}】${nm.name} 已达 ${nm.realm} 巅峰。`);
                    }
                }

                nm.cultivationProgress = newProgress;
                nm.subRealm = finalSubRealm;
            }

            // 处理休养生息自动切换
            if (nm.status === 'injured' && Math.random() > 0.4) {
                nm.status = 'healthy';
                turnLogs.push(`【${currentYear}载·${SEASON_NAMES[currentSeason]}】${nm.name} 伤势痊愈，回归洞府继续修行。`);
                nm.assignment = 'Cultivation';
            }

            return nm;
        });

        const newEvent = await generateYearlyEvent({ ...state, members: updatedMembers, regions: updatedRegions });

        setState(prev => {
            const finalHerbs = { ...prev.inventory.herbs };
            Object.entries(bonusInventory.herbs).forEach(([idStr, count]) => { 
                const id = parseInt(idStr);
                finalHerbs[id] = (finalHerbs[id] || 0) + count; 
            });
            const finalMinerals = { ...prev.inventory.minerals };
            Object.entries(bonusInventory.minerals).forEach(([idStr, count]) => { 
                const id = parseInt(idStr);
                finalMinerals[id] = (finalMinerals[id] || 0) + count; 
            });
            const finalPills = { ...prev.inventory.pills };
            Object.entries(bonusInventory.pills).forEach(([idStr, count]) => { 
                const id = parseInt(idStr);
                finalPills[id] = (finalPills[id] || 0) + count; 
            });
            const finalWeapons = { ...prev.inventory.weapons };
            Object.entries(bonusInventory.weapons).forEach(([idStr, count]) => { 
                const id = parseInt(idStr);
                finalWeapons[id] = (finalWeapons[id] || 0) + count; 
            });

            return {
                ...prev,
                year: isYearIncrement ? prev.year + 1 : prev.year,
                season: nextSeason,
                members: updatedMembers,
                buildings: updatedBuildings,
                regions: updatedRegions,
                spiritStones: prev.spiritStones + stoneGain,
                merit: prev.merit + meritGain,
                inventory: { 
                    ...prev.inventory, 
                    herbs: finalHerbs, 
                    minerals: finalMinerals,
                    pills: finalPills,
                    weapons: finalWeapons
                },
                logs: [...turnLogs, ...prev.logs].slice(0, 30)
            };
        });
        setEvent(newEvent);
        setIsProcessing(false);
    };

    const handleChoice = (choiceKey: 'choiceA' | 'choiceB') => {
        if (!event) return;
        const impact = event.impact as any;

        // 如果是游历事件，设置状态
        const travelTrigger = event.title?.includes('游历');

        setState(prev => {
            let updatedMembers = [...prev.members];
            if (travelTrigger && choiceKey === 'choiceA') {
                // 假设第一个选项是接受游历
                // 随机选一个处于Cultivation的成员
                const potential = updatedMembers.filter(m => m.assignment === 'Cultivation' && m.realm !== Realm.Mortal);
                if (potential.length > 0) {
                    const traveler = potential[Math.floor(Math.random() * potential.length)];
                    updatedMembers = updatedMembers.map(m => m.id === traveler.id ? { ...m, assignment: 'Travel' } : m);
                }
            } else if (travelTrigger && choiceKey === 'choiceB') {
                // 游历归来
                updatedMembers = updatedMembers.map(m => m.assignment === 'Travel' ? { ...m, assignment: 'Cultivation' } : m);
            }

            return {
                ...prev,
                spiritStones: prev.spiritStones + (impact.spiritStones || 0),
                merit: prev.merit + (impact.merit || 0),
                luck: prev.luck + (impact.luck || 0),
                members: updatedMembers,
                logs: [impact.log || `【${prev.year}载·因果】处理了：${event.title}`, ...prev.logs].slice(0, 30)
            };
        });
        setEvent(null);
    };

    const handleBreakthroughAttempt = (memberId: string, success: boolean) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            if (!member) return prev;

            let updatedMembers = [...prev.members];
            let newLog = '';

            if (success) {
                const currentRealmIdx = REALM_ORDER.indexOf(member.realm);
                const nextRealm = REALM_ORDER[currentRealmIdx + 1] || Realm.YuanShen;
                newLog = `【${prev.year}载·突破】${member.name} 突破至 ${nextRealm}。`;

                updatedMembers = updatedMembers.map(m => m.id === memberId ? {
                    ...m,
                    realm: nextRealm,
                    subRealm: 1,
                    cultivationProgress: 0,
                    maxAge: m.maxAge + 100, 
                    legacyPoints: (m.legacyPoints || 0) + 10
                } : m);
            } else {
                newLog = `【${prev.year}载·突破】${member.name}破镜失败，修为跌落。`;
                updatedMembers = updatedMembers.map(m => m.id === memberId ? {
                    ...m,
                    subRealm: 8,
                    cultivationProgress: 0,
                    status: 'injured',
                    assignment: 'Idle' // 自动转入休养
                } : m);
            }

            return {
                ...prev,
                members: updatedMembers,
                heritagePool: success ? prev.heritagePool + 10 : prev.heritagePool,
                logs: [newLog, ...prev.logs].slice(0, 30)
            };
        });
        setBreakingMemberId(null);
    };

    const handleUseHaotianMirror = () => {
        if (state.merit < 20) return;
        const undiscovered = state.regions.filter(r => !r.isDiscovered);
        if (undiscovered.length === 0) return;
        const reveal = undiscovered[Math.floor(Math.random() * undiscovered.length)];
        setState(prev => ({
            ...prev,
            merit: prev.merit - 20,
            regions: prev.regions.map(r => r.id === reveal.id ? { ...r, isDiscovered: true } : r),
            logs: [`【${prev.year}载·昊天镜】镜光照破了 ${reveal.name}。`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleSelectRegion = (r: Region | null) => {
        if (r && r.id === 'li_clan_home') {
            setIsManagementVisible(true);
            setState(p => ({ ...p, currentRegionId: '' }));
        } else {
            setState(p => ({ ...p, currentRegionId: r ? r.id : '' }));
        }
    };

    return (
        <div className="h-full w-full flex flex-col bg-[#0f0a07] text-gray-300 overflow-hidden select-none font-serif">
            <header className="h-16 bg-[#2c1810] border-b-2 border-yellow-900/50 flex items-center justify-between px-8 z-40 shadow-xl shrink-0">
                <div className="flex items-center gap-12">
                    <h1 className="text-2xl font-cursive text-yellow-500 tracking-widest">玄鉴仙族：昊天纪元</h1>
                    <div className="flex gap-6 items-center border-l border-yellow-900/30 pl-8">
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">家族灵石</span>
                            <span className="text-lg font-mono text-yellow-400">✨ {state.spiritStones}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">族中功德</span>
                            <span className="text-lg font-mono text-blue-400">💠 {state.merit}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">天罡历载</span>
                            <span className="text-lg font-mono text-yellow-100">{state.year} · <span className="text-yellow-500">{SEASON_NAMES[state.season]}</span></span>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <button onClick={handleUseHaotianMirror} disabled={state.merit < 20} className="px-5 py-2 bg-gradient-to-r from-blue-900 to-indigo-900 border border-blue-400 text-blue-100 rounded-full text-xs font-bold hover:brightness-125 transition-all shadow-[0_0_15px_rgba(59,130,246,0.4)] disabled:opacity-30">🪞 昊天镜 (20功德)</button>
                    <button onClick={() => setIsManagementVisible(true)} className="px-5 py-2 bg-black/40 border border-orange-900 text-orange-500 rounded-full text-xs font-bold hover:bg-orange-900/20 transition-all">🏛️ 家族管理</button>
                    <button onClick={() => setIsDashboardVisible(!isDashboardVisible)} className={`px-5 py-2 rounded-full border transition-all text-xs font-bold ${isDashboardVisible ? 'bg-yellow-800 border-yellow-500 text-yellow-100' : 'bg-black/40 border-yellow-900 text-gray-500'}`}>📜 族谱</button>
                    <button onClick={handleNextTurn} disabled={isProcessing || !!event} className="bg-gradient-to-b from-yellow-700 to-yellow-900 hover:from-yellow-600 hover:to-yellow-800 disabled:opacity-30 text-white px-8 py-2 rounded border-t border-yellow-500/30 border-b-4 border-black/50 font-bold transition-all text-sm shadow-lg">{isProcessing ? '推演中' : '岁时轮转'}</button>
                </div>
            </header>

            <main className="flex-1 flex overflow-hidden relative">
                <div className="flex-1 relative bg-[#0a0705]">
                    <WorldMap 
                        regions={state.regions} 
                        members={state.members} 
                        currentRegionId={state.currentRegionId} 
                        onSelectRegion={handleSelectRegion} 
                        onUpdateMember={handleUpdateMember} 
                        onUpdateRegion={(id, u) => setState(p => ({ ...p, regions: p.regions.map(r => r.id === id ? { ...r, ...u } : r) }))} 
                    />

                    <div className={`absolute bottom-6 left-6 transition-all duration-500 parchment border-2 border-[#4a3728] rounded-sm shadow-2xl z-20 opacity-95 flex flex-col overflow-hidden ${isConsoleCollapsed ? 'w-48 h-10' : 'w-72 h-64'}`}>
                        <div className="flex justify-between items-center px-4 py-2 border-b border-[#4a3728]/30 bg-black/5 shrink-0 cursor-pointer" onClick={() => setIsConsoleCollapsed(!isConsoleCollapsed)}>
                            <span className="text-[11px] text-[#2c1810] font-bold uppercase tracking-widest font-cursive">族史摘要</span>
                            <button className="text-[#4a3728] hover:text-black transition-transform duration-300" style={{ transform: isConsoleCollapsed ? 'rotate(180deg)' : 'rotate(0deg)' }}>▼</button>
                        </div>
                        {!isConsoleCollapsed && (
                            <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                                {state.logs.length > 0 ? state.logs.map((log, i) => (
                                    <p key={i} className="leading-relaxed text-black/80 font-serif font-bold text-[11px] border-b border-[#4a3728]/5 pb-1 animate-fade-in">
                                        <span className="text-[#8b0000] mr-2">◈</span> {log}
                                    </p>
                                )) : (
                                    <p className="text-gray-500 italic text-[10px] text-center py-10">暂无家族记载</p>
                                )}
                            </div>
                        )}
                    </div>
                </div>

                {isDashboardVisible && (
                    <div className="w-80 h-full border-l border-yellow-900/50 flex flex-col shrink-0">
                        <ClanDashboard 
                            state={state} 
                            onUpdateMember={handleUpdateMember} 
                            onAddMember={() => {}} 
                            onOpenBreakthrough={(id) => setBreakingMemberId(id)}
                        />
                    </div>
                )}
            </main>

            {isManagementVisible && (
                <ClanManagement 
                    state={state} 
                    onUpdateMember={handleUpdateMember} 
                    onUpdateBuilding={handleUpdateBuilding}
                    onAddBuilding={handleAddBuilding} 
                    onAssignBuilding={handleAssignBuilding} 
                    onClose={() => setIsManagementVisible(false)} 
                    onUnlockPosition={handleUnlockPosition}
                />
            )}

            {event && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
                    <div className="bg-[#f4e4bc] w-full max-w-2xl p-8 rounded border-[12px] border-[#4a3728] shadow-2xl relative animate-scale-in">
                        <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-[#4a3728] text-yellow-500 px-10 py-3 rounded-b-xl font-cursive text-2xl">{event.title}</div>
                        <div className="text-[#2c1810] leading-relaxed text-lg font-serif italic mb-8 max-h-[40vh] overflow-y-auto custom-scrollbar pr-4">{event.content}</div>
                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => handleChoice('choiceA')} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceA.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceA.effect}</p>
                            </button>
                            <button onClick={() => handleChoice('choiceB')} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceB.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceB.effect}</p>
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {breakingMemberId && (
                <BreakthroughModal 
                    member={state.members.find(m => m.id === breakingMemberId)!}
                    onClose={() => setBreakingMemberId(null)}
                    onAttempt={(success) => handleBreakthroughAttempt(breakingMemberId, success)}
                />
            )}
        </div>
    );
};

export default App;

