const getGradeStyle = (grade: number | string | undefined) => {
    const g = typeof grade === 'number' ? grade : (grade === '神器残片' ? 9 : 0);

    if (g <= 2) return {
        border: 'border-slate-300/60', text: 'text-slate-100', bg: 'bg-slate-900/60', hover: 'hover:border-slate-100', glow: 'shadow-[inset_0_0_10px_rgba(255,255,255,0.05)]', dropShadow: 'shadow-[0_0_5px_rgba(255,255,255,0.1)]'
    };
    if (g === 3) return {
        border: 'border-emerald-400/70', text: 'text-emerald-300', bg: 'bg-emerald-950/40', hover: 'hover:border-emerald-300', glow: 'shadow-[inset_0_0_12px_rgba(52,211,153,0.1)]', dropShadow: 'shadow-[0_0_8px_rgba(52,211,153,0.2)]'
    };
    if (g === 4) return {
        border: 'border-green-700/80', text: 'text-green-400', bg: 'bg-green-950/50', hover: 'hover:border-green-500', glow: 'shadow-[inset_0_0_15px_rgba(21,128,61,0.15)]', dropShadow: 'shadow-[0_0_10px_rgba(21,128,61,0.3)]'
    };
    if (g === 5) return {
        border: 'border-sky-400/80', text: 'text-sky-300', bg: 'bg-sky-950/40', hover: 'hover:border-sky-200', glow: 'shadow-[inset_0_0_15px_rgba(56,189,248,0.2)]', dropShadow: 'shadow-[0_0_12px_rgba(56,189,248,0.3)]'
    };
    if (g === 6) return {
        border: 'border-blue-700/90', text: 'text-blue-400', bg: 'bg-blue-950/50', hover: 'hover:border-blue-500', glow: 'shadow-[inset_0_0_18px_rgba(29,78,216,0.25)]', dropShadow: 'shadow-[0_0_15px_rgba(29,78,216,0.4)]'
    };
    if (g === 7) return {
        border: 'border-purple-600', text: 'text-purple-400', bg: 'bg-purple-950/40', hover: 'hover:border-purple-300', glow: 'shadow-[inset_0_0_20px_rgba(168,85,247,0.3)]', dropShadow: 'shadow-[0_0_18px_rgba(168,85,247,0.5)]'
    };
    if (g === 8) return {
        border: 'border-orange-500', text: 'text-orange-400', bg: 'bg-orange-950/40', hover: 'hover:border-orange-300', glow: 'shadow-[inset_0_0_22px_rgba(249,115,22,0.35)]', dropShadow: 'shadow-[0_0_20px_rgba(249,115,22,0.6)]'
    };
    return {
        border: 'border-red-600', text: 'text-red-500', bg: 'bg-red-950/50', hover: 'hover:border-red-400', glow: 'shadow-[inset_0_0_25px_rgba(220,38,38,0.4)]', dropShadow: 'shadow-[0_0_25px_rgba(239,68,68,0.7)]'
    };
};

