interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddMember: () => void;
    onOpenBreakthrough?: (id: string) => void;
}

const ITEMS_PER_PAGE = 8;
type BagSubTab = 'all' | 'equipment' | 'pills' | 'materials' | 'methods';
type SortKey = 'grade' | 'quantity' | 'name';

const ClanDashboard: React.FC<Props> = ({ state, onUpdateMember, onAddMember, onOpenBreakthrough }) => {
    const [selectedMemberId, setSelectedMemberId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'alive' | 'deceased'>('alive');
    const [currentPage, setCurrentPage] = useState(0);
    const [detailTab, setDetailTab] = useState<'attr' | 'talents' | 'status' | 'cultivation' | 'plan' | 'bag' | 'relations'>('attr');
    const [bagSubTab, setBagSubTab] = useState<BagSubTab>('all');
    const [bagSortKey, setBagSortKey] = useState<SortKey>('grade');

    const [focusedSlot, setFocusedSlot] = useState<string | null>(null);
    const [focusedEquipSlot, setFocusedEquipSlot] = useState<string | null>(null);
    const [focusedBagItem, setFocusedBagItem] = useState<number | null>(null);
    const [useQuantity, setUseQuantity] = useState<number>(1);
    const [libraryType, setLibraryType] = useState<MethodType>('Cultivation');

    // Tooltip State
    const [tooltip, setTooltip] = useState<{
        content: React.ReactNode;
        x: number;
        y: number;
        visible: boolean;
    } | null>(null);

    const selectedMember = useMemo(() => 
        state.members.find(m => m.id === selectedMemberId), 
    [state.members, selectedMemberId]);

    const filteredMembers = useMemo(() => {
        const list = state.members.filter(m => activeTab === 'alive' ? m.status !== 'dead' : m.status === 'dead');
        return list.sort((a, b) => {
            if (activeTab === 'alive') {
                const realmDiff = REALM_ORDER.indexOf(b.realm) - REALM_ORDER.indexOf(a.realm);
                if (realmDiff !== 0) return realmDiff;
                return b.subRealm - a.subRealm;
            }
            return (b.deathYear || 0) - (a.deathYear || 0);
        });
    }, [state.members, activeTab]);

    const pagedMembers = filteredMembers.slice(currentPage * ITEMS_PER_PAGE, (currentPage + 1) * ITEMS_PER_PAGE);

    const handleTabChange = (tab: 'alive' | 'deceased') => {
        setActiveTab(tab);
        setCurrentPage(0);
        setSelectedMemberId(null);
    };

    const isBreakthroughNeeded = (member: ClanMember) => {
        const realmIdx = REALM_ORDER.indexOf(member.realm);
        const req = getRequiredExp(realmIdx, member.subRealm);
        return member.subRealm === 9 && member.cultivationProgress >= req && member.realm !== Realm.YuanShen;
    };

    const toggleMethod = (methodId: number, type: MethodType) => {
        if (!selectedMember) return;

        const method = CULTIVATION_METHODS.find(m => m.id === methodId);
        if (method) {
            const meetsReq = checkMethodRequirements(selectedMember, method);
            if (!meetsReq) return;
        }

        if (type === 'Cultivation') {
            onUpdateMember(selectedMember.id, { mainMethodId: selectedMember.mainMethodId === methodId ? null : methodId });
        } else if (type === 'Movement') {
            onUpdateMember(selectedMember.id, { movementMethodId: selectedMember.movementMethodId === methodId ? null : methodId });
        } else if (type === 'Combat') {
            const currentAux = selectedMember.auxMethodIds;
            if (currentAux.includes(methodId)) {
                onUpdateMember(selectedMember.id, { auxMethodIds: currentAux.filter(mid => mid !== methodId) });
            } else if (currentAux.length < 4) {
                onUpdateMember(selectedMember.id, { auxMethodIds: [...currentAux, methodId] });
            }
        }
        setFocusedSlot(null);
    };

    const checkMethodRequirements = (member: ClanMember, method: CultivationMethod) => {
        const req = method.requirements;
        if (!req) return true;
        if (req.realm && REALM_ORDER.indexOf(member.realm) < REALM_ORDER.indexOf(req.realm)) return false;
        if (req.minRoots) {
            for (const [key, val] of Object.entries(req.minRoots)) {
                if ((member.roots as any)[key] < (val || 0)) return false;
            }
        }
        if (req.minRootGrade) {
            const grades: RootGrade[] = ['凡人', '伪灵根', '下品灵根', '中品灵根', '上品灵根', '极品灵根'];
            if (grades.indexOf(member.rootGrade) < grades.indexOf(req.minRootGrade)) return false;
        }
        return true;
    };

    const libraryMethods = useMemo(() => {
        if (!selectedMember) return [];
        return CULTIVATION_METHODS.filter(m => {
            if (m.type !== libraryType) return false;
            const isOwnedByClan = (state.inventory.methods[m.id] || 0) > 0;
            const isOwnedBySelf = (selectedMember.personalInventory.methods[m.id] || 0) > 0;
            const isEquipped = selectedMember.mainMethodId === m.id || 
                             selectedMember.movementMethodId === m.id || 
                             selectedMember.auxMethodIds.includes(m.id);
            return isOwnedByClan || isOwnedBySelf || isEquipped;
        }).map(m => {
            const totalCount = (state.inventory.methods[m.id] || 0) + (selectedMember.personalInventory.methods[m.id] || 0);
            return { ...m, totalCount };
        });
    }, [libraryType, selectedMember, state.inventory.methods]);

    const showTooltip = useCallback((e: React.MouseEvent, content: React.ReactNode) => {
        const rect = e.currentTarget.getBoundingClientRect();
        let x = rect.left + rect.width / 2;
        let y = rect.top;
        if (rect.top < 300) y = rect.bottom + 12; else y = rect.top - 12;
        const tooltipWidth = 260;
        if (x - tooltipWidth / 2 < 20) x = tooltipWidth / 2 + 20;
        if (x + tooltipWidth / 2 > window.innerWidth - 20) x = window.innerWidth - tooltipWidth / 2 - 20;
        setTooltip({ content, x, y, visible: true });
    }, []);

    const hideTooltip = useCallback(() => {
        setTooltip(prev => prev ? { ...prev, visible: false } : null);
    }, []);

    const renderMethodTooltipContent = (method: CultivationMethod) => {
        const req = method.requirements;
        const meetsRealm = !req?.realm || REALM_ORDER.indexOf(selectedMember?.realm || Realm.Mortal) >= REALM_ORDER.indexOf(req.realm);
        return (
            <div className="w-52 sm:w-64 font-serif">
                <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                    <span className="text-yellow-500 font-bold text-sm">{method.name}</span>
                    <span className={`text-[10px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(method.grade)}`}>
                        {getGradeText(method)}
                    </span>
                </div>
                <p className="text-[10px] sm:text-xs text-gray-200 mb-2 leading-relaxed italic">{method.desc}</p>
                <div className="mb-3 p-1.5 bg-black/30 border border-yellow-900/10 rounded">
                    <p className="text-[10px] text-orange-400 font-bold mb-1">【修炼要求】</p>
                    {req?.realm && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">境界要求</span>
                            <span className={meetsRealm ? 'text-green-500' : 'text-red-500'}>{req.realm}</span>
                        </div>
                    )}
                    {req?.minRootGrade && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">灵根等级</span>
                            <span className={`text-right ${selectedMember && (['凡人', '伪灵根', '下品灵根', '中品灵根', '上品灵根', '极品灵根'].indexOf(selectedMember.rootGrade) >= ['凡人', '伪灵根', '下品灵根', '中品灵根', '上品灵根', '极品灵根'].indexOf(req.minRootGrade)) ? 'text-gray-300' : 'text-red-500'}`}>{req.minRootGrade}</span>
                        </div>
                    )}
                </div>
                <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                    <p className="text-[10px] text-green-500 font-bold mb-1">【功法效果】</p>
                    {method.buffs.cultivationSpeed && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">修炼速度</span>
                            <span className={method.buffs.cultivationSpeed > 0 ? 'text-green-400' : 'text-red-400'}>
                                {method.buffs.cultivationSpeed > 0 ? '+' : ''}{method.buffs.cultivationSpeed}%
                            </span>
                        </div>
                    )}
                </div>
            </div>
        );
    };

    const renderItemTooltipContent = (itemId: number) => {
        const details = ALL_ITEM_DETAILS[itemId];
        if (!details) return <div className="p-2 text-xs">未知物品</div>;
        if (details.category === 'method') return renderMethodTooltipContent(details as unknown as CultivationMethod);
        const gradeStr = (details as any).gradeText || (details.grade !== undefined ? (typeof details.grade === 'number' ? `${details.grade}品` : details.grade) : '凡物');
        return (
            <div className="w-52 sm:w-64 font-serif">
                <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                    <span className="text-yellow-500 font-bold text-sm">{details.name}</span>
                    <span className={`text-[9px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(details.grade)}`}>{gradeStr}</span>
                </div>
                <p className="text-[10px] sm:text-xs text-gray-200 mb-4 leading-relaxed italic">{details.desc}</p>
            </div>
        );
    };

    const handleUnequip = (slot: keyof ClanMember['equippedItems']) => {
        if (!selectedMember) return;
        const itemId = selectedMember.equippedItems[slot];
        if (itemId === null) return;
        const newEquipped = { ...selectedMember.equippedItems, [slot]: null };
        const newInventory = { ...selectedMember.personalInventory };
        newInventory.weapons[itemId] = (newInventory.weapons[itemId] || 0) + 1;
        onUpdateMember(selectedMember.id, { equippedItems: newEquipped, personalInventory: newInventory });
        setFocusedEquipSlot(null);
    };

    const handleEquip = (itemId: number, category: 'weapon' | 'armor' | 'accessory' | 'treasure') => {
        if (!selectedMember) return;
        const newEquipped = { ...selectedMember.equippedItems };
        const newInventory = { ...selectedMember.personalInventory };
        const currentItemId = newEquipped[category];
        if (currentItemId !== null) newInventory.weapons[currentItemId] = (newInventory.weapons[currentItemId] || 0) + 1;
        if (newInventory.weapons[itemId] > 0) {
            newInventory.weapons[itemId]--;
            if (newInventory.weapons[itemId] === 0) delete newInventory.weapons[itemId];
        }
        newEquipped[category] = itemId;
        onUpdateMember(selectedMember.id, { equippedItems: newEquipped, personalInventory: newInventory });
        setFocusedBagItem(null);
    };

    const handleUsePill = (pillId: number, quantity: number) => {
        if (!selectedMember) return;
        const pillData = PILL_DETAILS[pillId] as any;
        if (!pillData) return;
        if (pillData.requiredRealm && selectedMember.realm !== pillData.requiredRealm) {
            setFocusedBagItem(null);
            hideTooltip();
            return;
        }
        const newInventory = { ...selectedMember.personalInventory };
        const currentCount = newInventory.pills[pillId] || 0;
        if (currentCount < quantity) return;
        newInventory.pills[pillId] -= quantity;
        if (newInventory.pills[pillId] === 0) delete newInventory.pills[pillId];
        const updates: Partial<ClanMember> = { personalInventory: newInventory };
        const pillEffects = pillData.effects;
        if (pillEffects) {
            if (pillEffects.cultivationProgress) updates.cultivationProgress = (selectedMember.cultivationProgress || 0) + (pillEffects.cultivationProgress * quantity);
            if (pillEffects.status) updates.status = pillEffects.status;
            if (pillEffects.maxAge) updates.maxAge = (selectedMember.maxAge || 0) + (pillEffects.maxAge * quantity);
            if (pillEffects.divineSense) updates.divineSense = (selectedMember.divineSense || 0) + (pillEffects.divineSense * quantity);
        }
        onUpdateMember(selectedMember.id, updates);
        setFocusedBagItem(null); setUseQuantity(1); hideTooltip();
    };

    const renderNamePlaque = (member: ClanMember) => (
        <div className={`border-2 border-black bg-red-950/60 px-6 py-2 shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-sm ${member.tier === '绝世天骄' ? 'ring-1 ring-red-500/50' : ''}`}>
            <h2 className="text-xl sm:text-2xl lg:text-3xl font-cursive tracking-wider text-center whitespace-nowrap">
                <span className="text-yellow-400">{member.name}</span>
                {member.title && <><span className="mx-1 text-black font-bold">·</span><span className={`${getTitleColor(member.tier)}`}>{member.title}</span></>}
            </h2>
        </div>
    );

    const renderSlotItem = (methodId: number | null, type: MethodType, label: string, slotKey: string) => {
        const method = CULTIVATION_METHODS.find(m => m.id === methodId);
        const isFocused = focusedSlot === slotKey;
        const style = method ? getGradeStyle(method.grade) : null;
        return (
            <div className="flex flex-col items-center gap-1 group relative">
                <div onClick={() => methodId !== null && setFocusedSlot(isFocused ? null : slotKey)}
                    onMouseEnter={(e) => method && showTooltip(e, renderMethodTooltipContent(method))}
                    onMouseLeave={hideTooltip}
                    className={`relative cursor-pointer transition-all duration-300 rounded-md border-2 flex items-center justify-center w-12 h-12 sm:w-14 sm:h-14 ${isFocused ? 'border-yellow-500 shadow-[0_0_10px_rgba(234,179,8,0.5)]' : (style ? style.border : 'border-yellow-900/20')} ${style ? style.bg : 'bg-black/40'} overflow-hidden`}>
                    {method ? <div className={`w-full h-full p-1 flex flex-col items-center justify-center text-center font-bold ${style?.text}`}>📜<span className="text-[7px] sm:text-[8px] leading-tight line-clamp-2 mt-0.5">{method.name}</span></div> : <div className="text-gray-800 text-[8px] sm:text-[9px] opacity-20 italic font-bold">{label}</div>}
                    {methodId !== null && isFocused && (
                        <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center p-0.5 animate-fade-in z-20">
                            <button onClick={(e) => { e.stopPropagation(); if (methodId !== null) toggleMethod(methodId, type); hideTooltip(); }} className="bg-red-900/80 hover:bg-red-700 text-white text-[7px] py-0.5 px-1 rounded-full border border-red-500/50">卸下</button>
                        </div>
                    )}
                </div>
                <div className="bg-black/60 px-1 py-0.5 rounded-full border border-yellow-900/40 shadow-sm"><span className="text-[7px] sm:text-[8px] text-yellow-500/80 font-bold whitespace-nowrap">{label}</span></div>
            </div>
        );
    };

    const renderEquipSlot = (itemId: number | null, label: string, icon: string, slotKey: keyof ClanMember['equippedItems']) => {
        const isFocused = focusedEquipSlot === slotKey;
        const itemDetails = itemId !== null ? ALL_ITEM_DETAILS[itemId] : null;
        const style = itemDetails ? getGradeStyle(itemDetails.grade) : null;
        return (
            <div className="flex flex-col items-center gap-1 relative">
                <div onClick={() => itemId !== null && setFocusedEquipSlot(isFocused ? null : slotKey)}
                    onMouseEnter={(e) => itemId !== null && showTooltip(e, renderItemTooltipContent(itemId))}
                    onMouseLeave={hideTooltip}
                    className={`w-12 h-12 sm:w-16 sm:h-16 rounded border-2 flex items-center justify-center transition-all cursor-pointer relative overflow-hidden ${itemDetails ? `${style?.border} ${style?.text} ${style?.bg}` : 'bg-black/40 border-white/10 text-gray-800'}`}>
                    <span className="font-bold text-[10px] px-1 text-center leading-tight">{itemDetails ? itemDetails.name : icon}</span>
                </div>
                {itemId !== null && isFocused && <button onClick={(e) => { e.stopPropagation(); handleUnequip(slotKey); hideTooltip(); }} className={`absolute top-1/2 -translate-y-1/2 z-30 bg-red-800 text-white text-[10px] py-1 px-2 rounded-sm font-bold shadow-lg border border-red-500 ${slotKey === 'weapon' || slotKey === 'armor' ? '-right-10' : '-left-10'}`}>卸下</button>}
                <span className="text-[10px] text-gray-600 mt-1">{label}</span>
            </div>
        );
    };

    const renderBagItem = (icon: string, id: number, count: number, onAction?: (qty: number) => void, actionLabel?: string) => {
        const details = ALL_ITEM_DETAILS[id] as any;
        if (!details) return null;
        const style = getGradeStyle(details.grade);
        const isRestricted = details.requiredRealm && selectedMember?.realm !== details.requiredRealm;
        return (
            <div key={id} onClick={() => setFocusedBagItem(focusedBagItem === id ? null : id)}
                onMouseEnter={(e) => showTooltip(e, renderItemTooltipContent(id))}
                onMouseLeave={hideTooltip}
                className={`${style.bg} border-2 ${style.border} p-3 rounded-lg flex flex-col items-center transition-all aspect-[4/5] justify-between shadow-lg relative overflow-hidden ${isRestricted ? 'opacity-50 grayscale' : ''}`}>
                <div className="text-3xl mt-2">{icon}</div>
                <span className={`text-[12px] font-bold text-center truncate w-full mt-2 px-1 ${style.text}`}>{details.name}</span>
                <span className="text-[11px] font-bold text-yellow-600/80 mt-auto font-mono">数量：{count}</span>
                {onAction && focusedBagItem === id && (
                    <div className="absolute inset-0 bg-black/90 flex flex-col items-center justify-center z-10 p-2">
                        {isRestricted ? <div className="text-red-500 text-[10px] font-bold">境界不足</div> : 
                        <button onClick={(e) => { e.stopPropagation(); onAction(useQuantity); hideTooltip(); }} className="text-white text-[11px] py-1.5 px-3 rounded font-bold w-full bg-yellow-800">服用/佩戴</button>}
                        <button onClick={(e) => { e.stopPropagation(); setFocusedBagItem(null); }} className="mt-1 text-[9px] text-gray-500">取消</button>
                    </div>
                )}
            </div>
        );
    };

    const sortedBagItems = useMemo(() => {
        if (!selectedMember) return [];
        const inv = selectedMember.personalInventory;
        const itemsList: Array<{ id: number; count: number; category: BagSubTab }> = [];
        const addItems = (record: Record<number, number>, category: BagSubTab) => Object.entries(record).forEach(([id, count]) => { if (count > 0) itemsList.push({ id: parseInt(id), count, category }); });
        if (bagSubTab === 'all' || bagSubTab === 'equipment') addItems(inv.weapons, 'equipment');
        if (bagSubTab === 'all' || bagSubTab === 'pills') addItems(inv.pills, 'pills');
        if (bagSubTab === 'all' || bagSubTab === 'materials') { addItems(inv.herbs, 'materials'); addItems(inv.minerals, 'materials'); }
        if (bagSubTab === 'all' || bagSubTab === 'methods') addItems(inv.methods, 'methods');
        return itemsList.sort((a, b) => (ALL_ITEM_DETAILS[b.id]?.grade || 0) - (ALL_ITEM_DETAILS[a.id]?.grade || 0));
    }, [selectedMember, bagSubTab]);

    const renderStatusTab = () => {
        if (!selectedMember) return null;
        const statusInfo = TASK_INFO[selectedMember.assignment];
        const multiplier = selectedMember.assignment === 'Cultivation' ? '100%' :
                          selectedMember.assignment === 'Idle' ? '20%' :
                          (selectedMember.assignment === 'Alchemy' || selectedMember.assignment === 'Smithing' || selectedMember.assignment === 'Research') ? '60%' :
                          selectedMember.assignment === 'Mission' ? '40%' :
                          selectedMember.assignment === 'Travel' ? '10%' : '0%';

        return (
            <div className="h-full flex flex-col animate-fade-in p-4 space-y-6">
                <div className="bg-black/30 border-2 border-yellow-900/20 p-6 rounded-xl text-center">
                    <h4 className="text-gray-500 text-xs uppercase tracking-widest mb-2">当前人物状态</h4>
                    <p className={`text-4xl font-cursive ${statusInfo.color} mb-4`}>{statusInfo.label}</p>
                    <div className="h-px bg-yellow-900/10 w-24 mx-auto mb-4"></div>
                    <p className="text-sm text-gray-400 italic leading-relaxed px-4">{statusInfo.desc}</p>
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div className="bg-black/40 p-4 rounded-lg border border-white/5">
                        <p className="text-[10px] text-gray-500 mb-1">修行效率</p>
                        <p className="text-2xl font-mono text-yellow-500 font-bold">{multiplier}</p>
                    </div>
                    <div className="bg-black/40 p-4 rounded-lg border border-white/5">
                        <p className="text-[10px] text-gray-500 mb-1">因果牵引</p>
                        <p className="text-2xl font-mono text-blue-500 font-bold">1.0x</p>
                    </div>
                </div>

                <div className="flex-1 border-t border-yellow-900/10 pt-4">
                    <h5 className="text-xs text-yellow-600 font-bold mb-4">状态自动流转说明</h5>
                    <ul className="text-[11px] text-gray-500 space-y-2 list-disc pl-4">
                        <li><span className="text-blue-400">闭关修炼</span>：默认修行状态。</li>
                        <li><span className="text-emerald-400">休养生息</span>：重伤后自动切换，无法手动更改。</li>
                        <li><span className="text-pink-400">炼丹/炼器/研习</span>：担任对应家族职司后开启。</li>
                        <li><span className="text-orange-400">外出派遣</span>：执行领地任务期间生效。</li>
                        <li><span className="text-yellow-500">外出游历</span>：突发事件触发，可能获得奇遇。</li>
                    </ul>
                </div>
            </div>
        );
    };

    return (
        <div className="bg-[#1e130c] border-l-4 border-yellow-800 h-full flex flex-col relative overflow-hidden font-serif">
            {tooltip && tooltip.visible && <div className="fixed z-[10000] pointer-events-none bg-black/95 border-2 border-yellow-900/50 p-4 rounded shadow-2xl animate-fade-in" style={{ left: tooltip.x, top: tooltip.y, transform: `translate(-50%, ${tooltip.y > window.innerHeight / 2 ? '-100%' : '0'})` }}>{tooltip.content}</div>}
            <div className="p-4 border-b border-yellow-900/30 bg-black/40 shrink-0">
                <h2 className="text-xl font-cursive text-yellow-500 mb-4">⛩️ 族谱常青</h2>
                <div className="flex p-1 bg-black/40 rounded-lg gap-1 border border-yellow-900/10">
                    <button onClick={() => handleTabChange('alive')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'alive' ? 'bg-yellow-800 text-yellow-100' : 'text-gray-500'}`}>在世族人</button>
                    <button onClick={() => handleTabChange('deceased')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'deceased' ? 'bg-gray-800 text-gray-100' : 'text-gray-500'}`}>英灵祠堂</button>
                </div>
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar">
                {pagedMembers.map(m => (
                    <div key={m.id} onClick={() => activeTab === 'alive' && setSelectedMemberId(m.id)} className={`p-3 rounded-md border transition-all cursor-pointer ${selectedMemberId === m.id ? 'bg-[#2d1e15] border-yellow-600' : 'bg-[#1e130c] border-yellow-900/30'}`}>
                        <div className="flex justify-between items-start">
                            <span className="font-bold text-sm text-yellow-100">{m.name}</span>
                            <span className={`text-[10px] ${TASK_INFO[m.assignment].color}`}>{TASK_INFO[m.assignment].label}</span>
                        </div>
                        <div className="flex justify-between text-[10px] mt-2">
                            <span className={getRealmStyle(m.realm).split(' ')[2]}>{getRealmText(m.realm, m.subRealm)}</span>
                            <span className={getTierColor(m.tier)}>{m.tier}</span>
                        </div>
                    </div>
                ))}
            </div>
            {selectedMember && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 p-4 overflow-hidden">
                    <div className="relative w-full max-w-6xl h-full bg-[#1a2521] border-[12px] border-[#2c3e34] rounded-sm flex flex-col">
                        <div className="h-16 bg-[#141e1b] border-b border-[#2c3e34] flex items-center px-8 shrink-0">
                            <div className="flex gap-4 h-full">
                                {['attr', 'status', 'talents', 'relations', 'cultivation', 'bag', 'plan'].map(t => (
                                    <button key={t} onClick={() => setDetailTab(t as any)} className={`px-4 h-full text-xs font-bold border-b-4 ${detailTab === t ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500'}`}>
                                        {t === 'attr' ? '👤 属性' : t === 'status' ? '✨ 状态' : t === 'talents' ? '📜 天赋' : t === 'relations' ? '🤝 关系' : t === 'cultivation' ? '🌀 功法' : t === 'bag' ? '🎒 行囊' : '🗺️ 计划'}
                                    </button>
                                ))}
                            </div>
                            <button onClick={() => setSelectedMemberId(null)} className="ml-auto w-9 h-9 bg-red-900/20 text-red-500 rounded-full flex items-center justify-center text-xl font-bold">×</button>
                        </div>
                        <div className="flex-1 flex overflow-hidden">
                            <div className="w-[35%] border-r border-[#2c3e34] p-8 bg-black/10 flex flex-col items-center">
                                {renderNamePlaque(selectedMember)}
                                <div className="relative flex items-center justify-center gap-6 py-8">
                                    <div className="flex flex-col gap-8">{renderEquipSlot(selectedMember.equippedItems.weapon, '武器', '⚔️', 'weapon')}{renderEquipSlot(selectedMember.equippedItems.armor, '防具', '🛡️', 'armor')}</div>
                                    <div className="w-44 h-64 bg-black/40 rounded-full border-2 border-yellow-900/20 flex items-center justify-center text-7xl opacity-10">🧘</div>
                                    <div className="flex flex-col gap-8">{renderEquipSlot(selectedMember.equippedItems.accessory, '饰品', '💍', 'accessory')}{renderEquipSlot(selectedMember.equippedItems.treasure, '法宝', '🔮', 'treasure')}</div>
                                </div>
                                <div className="w-full mt-4 p-4 bg-black/30 border border-yellow-900/10 rounded">
                                    <div className="flex justify-between items-center mb-2"><span className="text-[10px] text-gray-500 font-bold">修为进度</span></div>
                                    <div className="w-full h-2 bg-gray-900 rounded-full overflow-hidden border border-white/10"><div className="h-full bg-blue-600" style={{ width: `${(selectedMember.cultivationProgress / getRequiredExp(REALM_ORDER.indexOf(selectedMember.realm), selectedMember.subRealm)) * 100}%` }}></div></div>
                                </div>
                            </div>
                            <div className="flex-1 p-8 overflow-y-auto custom-scrollbar bg-[#1a2521]/50">
                                {detailTab === 'status' ? renderStatusTab() : detailTab === 'bag' ? <div className="grid grid-cols-4 gap-4">{sortedBagItems.map(item => renderBagItem('📦', item.id, item.count))}</div> : <p className="text-gray-500 italic text-center py-20">此处暂未开放详细内容...</p>}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ClanDashboard;

import React, { useState, useMemo, useCallback } from 'react';
import { GameState, ClanMember, Realm, TaskType, DevelopmentPlan, CultivationMethod, MethodType, TalentTier, RootGrade, SpecializedTalents } from '../types';
import { 
    TASK_INFO, REALM_ORDER, DEVELOPMENT_PLANS, CULTIVATION_METHODS, 
    PHYSIQUE_DETAILS, ABILITY_DETAILS, getArtisanTitle, getArtisanBonus, 
    getWeaponMasteryTitle, getWeaponTalentBonus, 
    PILL_DETAILS, HERB_DETAILS, 
    GENERATIONS, ALL_ITEM_DETAILS
} from '../constants';
import { getRequiredExp } from './CultivationSystem';

/**
 * 根据品级获取对应的UI样式
 */
const getGradeStyle = (grade: number | string | undefined) => {
    const g = typeof grade === 'number' ? grade : (grade === '神器残片' ? 9 : 0);

    if (g <= 2) return {
        border: 'border-slate-300/60', text: 'text-slate-100', bg: 'bg-slate-900/60', hover: 'hover:border-slate-100', glow: 'shadow-[inset_0_0_10px_rgba(255,255,255,0.05)]', dropShadow: 'shadow-[0_0_5px_rgba(255,255,255,0.1)]'
    };
    if (g === 3) return {
        border: 'border-emerald-400/70', text: 'text-emerald-300', bg: 'bg-emerald-950/40', hover: 'hover:border-emerald-300', glow: 'shadow-[inset_0_0_12px_rgba(52,211,153,0.1)]', dropShadow: 'shadow-[0_0_8px_rgba(52,211,153,0.2)]'
    };
    if (g === 4) return {
        border: 'border-green-700/80', text: 'text-green-400', bg: 'bg-green-950/50', hover: 'hover:border-green-500', glow: 'shadow-[inset_0_0_15px_rgba(21,128,61,0.15)]', dropShadow: 'shadow-[0_0_10px_rgba(21,128,61,0.3)]'
    };
    if (g === 5) return {
        border: 'border-sky-400/80', text: 'text-sky-300', bg: 'bg-sky-950/40', hover: 'hover:border-sky-200', glow: 'shadow-[inset_0_0_15px_rgba(56,189,248,0.2)]', dropShadow: 'shadow-[0_0_12px_rgba(56,189,248,0.3)]'
    };
    if (g === 6) return {
        border: 'border-blue-700/90', text: 'text-blue-400', bg: 'bg-blue-950/50', hover: 'hover:border-blue-500', glow: 'shadow-[inset_0_0_18px_rgba(29,78,216,0.25)]', dropShadow: 'shadow-[0_0_15px_rgba(29,78,216,0.4)]'
    };
    if (g === 7) return {
        border: 'border-purple-600', text: 'text-purple-400', bg: 'bg-purple-950/40', hover: 'hover:border-purple-300', glow: 'shadow-[inset_0_0_20px_rgba(168,85,247,0.3)]', dropShadow: 'shadow-[0_0_18px_rgba(168,85,247,0.5)]'
    };
    if (g === 8) return {
        border: 'border-orange-500', text: 'text-orange-400', bg: 'bg-orange-950/40', hover: 'hover:border-orange-300', glow: 'shadow-[inset_0_0_22px_rgba(249,115,22,0.35)]', dropShadow: 'shadow-[0_0_20px_rgba(249,115,22,0.6)]'
    };
    return {
        border: 'border-red-600', text: 'text-red-500', bg: 'bg-red-950/50', hover: 'hover:border-red-400', glow: 'shadow-[inset_0_0_25px_rgba(220,38,38,0.4)]', dropShadow: 'shadow-[0_0_25px_rgba(239,68,68,0.7)]'
    };
};

const getGradeColor = (grade: number | string | undefined) => {
    const style = getGradeStyle(grade);
    return `${style.border} ${style.text} ${style.dropShadow}`;
};

const getTierColor = (tier: TalentTier) => {
    switch (tier) {
        case '凡人': return 'text-slate-400';
        case '平庸': return 'text-gray-300';
        case '普通': return 'text-emerald-500';
        case '超凡': return 'text-sky-500';
        case '天才': return 'text-purple-500';
        case '绝世': return 'text-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.4)]';
        case '绝世天骄': return 'text-rose-500 animate-pulse font-black shadow-[0_0_12px_rgba(244,63,94,0.6)]';
        default: return 'text-gray-400';
    }
};

const getTitleColor = (tier: TalentTier) => {
    switch (tier) {
        case '凡人': return 'text-white';
        case '平庸': return 'text-green-500';
        case '普通': return 'text-blue-400';
        case '超凡': return 'text-purple-500';
        case '天才': return 'text-orange-500';
        case '绝世': return 'text-amber-400';
        case '绝世天骄': return 'text-red-600';
        default: return 'text-white';
    }
};

const getRootGradeColor = (grade: RootGrade) => {
    switch (grade) {
        case '凡人': return 'text-slate-500';
        case '伪灵根': return 'text-gray-400';
        case '下品灵根': return 'text-emerald-600';
        case '中品灵根': return 'text-sky-600';
        case '上品灵根': return 'text-purple-600';
        case '极品灵根': return 'text-amber-600 font-bold';
        default: return 'text-gray-400';
    }
};

const getRealmStyle = (realm: Realm) => {
    if (realm === Realm.Mortal) return "border-[#4a3728] bg-[#2c1810] text-[#8c6b4f]";
    return "border-[#6b4e31] bg-[#3d2b1f] text-[#c9a063]";
};

const getRealmText = (realm: Realm, subRealm: number) => {
    if (realm === Realm.Mortal) return '凡人';
    return `${realm}${subRealm}层`;
};

const getGradeText = (method: CultivationMethod) => {
    const numerals = ['','一','二','三','四','五','六','七','八','九'];
    return `${numerals[method.grade]}品${method.quality}`;
};

const getElementColorClass = (key: string, val: number) => {
    if (val === 0) return 'text-gray-600 border-gray-800 opacity-30';
    switch (key) {
        case 'gold': return 'text-yellow-400 border-yellow-500 bg-yellow-500/10';
        case 'wood': return 'text-green-400 border-green-500 bg-green-500/10';
        case 'water': return 'text-blue-400 border-blue-500 bg-blue-500/10';
        case 'fire': return 'text-red-400 border-red-500 bg-red-500/10';
        case 'earth': return 'text-orange-700 border-orange-800 bg-orange-800/10';
        default: return 'text-gray-400 border-gray-500';
    }
};

const getElementName = (key: string) => {
    switch (key) {
        case 'gold': return '金';
        case 'wood': return '木';
        case 'water': return '水';
        case 'fire': return '火';
        case 'earth': return '土';
        default: return key;
    }
};

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddMember: () => void;
    onOpenBreakthrough?: (id: string) => void;
}

const ITEMS_PER_PAGE = 8;
type BagSubTab = 'all' | 'equipment' | 'pills' | 'materials' | 'methods';
type SortKey = 'grade' | 'quantity' | 'name';

const ClanDashboard: React.FC<Props> = ({ state, onUpdateMember, onAddMember, onOpenBreakthrough }) => {
    const [selectedMemberId, setSelectedMemberId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'alive' | 'deceased'>('alive');
    const [currentPage, setCurrentPage] = useState(0);
    const [detailTab, setDetailTab] = useState<'attr' | 'talents' | 'status' | 'cultivation' | 'plan' | 'bag' | 'relations'>('attr');
    const [bagSubTab, setBagSubTab] = useState<BagSubTab>('all');
    const [bagSortKey, setBagSortKey] = useState<SortKey>('grade');

    const [focusedSlot, setFocusedSlot] = useState<string | null>(null);
    const [focusedEquipSlot, setFocusedEquipSlot] = useState<string | null>(null);
    const [focusedBagItem, setFocusedBagItem] = useState<number | null>(null);
    const [useQuantity, setUseQuantity] = useState<number>(1);
    const [libraryType, setLibraryType] = useState<MethodType>('Cultivation');

    // Tooltip State
    const [tooltip, setTooltip] = useState<{
        content: React.ReactNode;
        x: number;
        y: number;
        visible: boolean;
    } | null>(null);

    const selectedMember = useMemo(() => 
        state.members.find(m => m.id === selectedMemberId), 
    [state.members, selectedMemberId]);

    const filteredMembers = useMemo(() => {
        const list = state.members.filter(m => activeTab === 'alive' ? m.status !== 'dead' : m.status === 'dead');
        return list.sort((a, b) => {
            if (activeTab === 'alive') {
                const realmDiff = REALM_ORDER.indexOf(b.realm) - REALM_ORDER.indexOf(a.realm);
                if (realmDiff !== 0) return realmDiff;
                return b.subRealm - a.subRealm;
            }
            return (b.deathYear || 0) - (a.deathYear || 0);
        });
    }, [state.members, activeTab]);

    const pagedMembers = filteredMembers.slice(currentPage * ITEMS_PER_PAGE, (currentPage + 1) * ITEMS_PER_PAGE);

    const handleTabChange = (tab: 'alive' | 'deceased') => {
        setActiveTab(tab);
        setCurrentPage(0);
        setSelectedMemberId(null);
    };

    const isBreakthroughNeeded = (member: ClanMember) => {
        const realmIdx = REALM_ORDER.indexOf(member.realm);
        const req = getRequiredExp(realmIdx, member.subRealm);
        return member.subRealm === 9 && member.cultivationProgress >= req && member.realm !== Realm.YuanShen;
    };

    const toggleMethod = (methodId: number, type: MethodType) => {
        if (!selectedMember) return;

        const method = CULTIVATION_METHODS.find(m => m.id === methodId);
        if (method) {
            const meetsReq = checkMethodRequirements(selectedMember, method);
            if (!meetsReq) return;
        }

        if (type === 'Cultivation') {
            onUpdateMember(selectedMember.id, { mainMethodId: selectedMember.mainMethodId === methodId ? null : methodId });
        } else if (type === 'Movement') {
            onUpdateMember(selectedMember.id, { movementMethodId: selectedMember.movementMethodId === methodId ? null : methodId });
        } else if (type === 'Combat') {
            const currentAux = selectedMember.auxMethodIds;
            if (currentAux.includes(methodId)) {
                onUpdateMember(selectedMember.id, { auxMethodIds: currentAux.filter(mid => mid !== methodId) });
            } else if (currentAux.length < 4) {
                onUpdateMember(selectedMember.id, { auxMethodIds: [...currentAux, methodId] });
            }
        }
        setFocusedSlot(null);
    };

    const checkMethodRequirements = (member: ClanMember, method: CultivationMethod) => {
        const req = method.requirements;
        if (!req) return true;
        if (req.realm && REALM_ORDER.indexOf(member.realm) < REALM_ORDER.indexOf(req.realm)) return false;
        if (req.minRoots) {
            for (const [key, val] of Object.entries(req.minRoots)) {
                if ((member.roots as any)[key] < (val || 0)) return false;
            }
        }
        if (req.minRootGrade) {
            const grades: RootGrade[] = ['凡人', '伪灵根', '下品灵根', '中品灵根', '上品灵根', '极品灵根'];
            if (grades.indexOf(member.rootGrade) < grades.indexOf(req.minRootGrade)) return false;
        }
        return true;
    };

    const libraryMethods = useMemo(() => {
        if (!selectedMember) return [];
        return CULTIVATION_METHODS.filter(m => {
            if (m.type !== libraryType) return false;
            const isOwnedByClan = (state.inventory.methods[m.id] || 0) > 0;
            const isOwnedBySelf = (selectedMember.personalInventory.methods[m.id] || 0) > 0;
            const isEquipped = selectedMember.mainMethodId === m.id || 
                             selectedMember.movementMethodId === m.id || 
                             selectedMember.auxMethodIds.includes(m.id);
            return isOwnedByClan || isOwnedBySelf || isEquipped;
        }).map(m => {
            const totalCount = (state.inventory.methods[m.id] || 0) + (selectedMember.personalInventory.methods[m.id] || 0);
            return { ...m, totalCount };
        });
    }, [libraryType, selectedMember, state.inventory.methods]);

    const showTooltip = useCallback((e: React.MouseEvent, content: React.ReactNode) => {
        const rect = e.currentTarget.getBoundingClientRect();
        let x = rect.left + rect.width / 2;
        let y = rect.top;
        if (rect.top < 300) y = rect.bottom + 12; else y = rect.top - 12;
        const tooltipWidth = 260;
        if (x - tooltipWidth / 2 < 20) x = tooltipWidth / 2 + 20;
        if (x + tooltipWidth / 2 > window.innerWidth - 20) x = window.innerWidth - tooltipWidth / 2 - 20;
        setTooltip({ content, x, y, visible: true });
    }, []);

    const hideTooltip = useCallback(() => {
        setTooltip(prev => prev ? { ...prev, visible: false } : null);
    }, []);

    const renderMethodTooltipContent = (method: CultivationMethod) => {
        const req = method.requirements;
        const meetsRealm = !req?.realm || REALM_ORDER.indexOf(selectedMember?.realm || Realm.Mortal) >= REALM_ORDER.indexOf(req.realm);
        return (
            <div className="w-52 sm:w-64 font-serif">
                <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                    <span className="text-yellow-500 font-bold text-sm">{method.name}</span>
                    <span className={`text-[10px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(method.grade)}`}>
                        {getGradeText(method)}
                    </span>
                </div>
                <p className="text-[10px] sm:text-xs text-gray-200 mb-2 leading-relaxed italic">{method.desc}</p>
                <div className="mb-3 p-1.5 bg-black/30 border border-yellow-900/10 rounded">
                    <p className="text-[10px] text-orange-400 font-bold mb-1">【修炼要求】</p>
                    {req?.realm && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">境界要求</span>
                            <span className={meetsRealm ? 'text-green-500' : 'text-red-500'}>{req.realm}</span>
                        </div>
                    )}
                    {req?.minRootGrade && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">灵根等级</span>
                            <span className={`text-right ${selectedMember && (['凡人', '伪灵根', '下品灵根', '中品灵根', '上品灵根', '极品灵根'].indexOf(selectedMember.rootGrade) >= ['凡人', '伪灵根', '下品灵根', '中品灵根', '上品灵根', '极品灵根'].indexOf(req.minRootGrade)) ? 'text-gray-300' : 'text-red-500'}`}>{req.minRootGrade}</span>
                        </div>
                    )}
                </div>
                <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                    <p className="text-[10px] text-green-500 font-bold mb-1">【功法效果】</p>
                    {method.buffs.cultivationSpeed && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">修炼速度</span>
                            <span className={method.buffs.cultivationSpeed > 0 ? 'text-green-400' : 'text-red-400'}>
                                {method.buffs.cultivationSpeed > 0 ? '+' : ''}{method.buffs.cultivationSpeed}%
                            </span>
                        </div>
                    )}
                </div>
            </div>
        );
    };

    const renderItemTooltipContent = (itemId: number) => {
        const details = ALL_ITEM_DETAILS[itemId];
        if (!details) return <div className="p-2 text-xs">未知物品</div>;
        if (details.category === 'method') return renderMethodTooltipContent(details as unknown as CultivationMethod);
        const gradeStr = (details as any).gradeText || (details.grade !== undefined ? (typeof details.grade === 'number' ? `${details.grade}品` : details.grade) : '凡物');
        return (
            <div className="w-52 sm:w-64 font-serif">
                <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                    <span className="text-yellow-500 font-bold text-sm">{details.name}</span>
                    <span className={`text-[9px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(details.grade)}`}>{gradeStr}</span>
                </div>
                <p className="text-[10px] sm:text-xs text-gray-200 mb-4 leading-relaxed italic">{details.desc}</p>
            </div>
        );
    };

    const handleUnequip = (slot: keyof ClanMember['equippedItems']) => {
        if (!selectedMember) return;
        const itemId = selectedMember.equippedItems[slot];
        if (itemId === null) return;
        const newEquipped = { ...selectedMember.equippedItems, [slot]: null };
        const newInventory = { ...selectedMember.personalInventory };
        newInventory.weapons[itemId] = (newInventory.weapons[itemId] || 0) + 1;
        onUpdateMember(selectedMember.id, { equippedItems: newEquipped, personalInventory: newInventory });
        setFocusedEquipSlot(null);
    };

    const handleEquip = (itemId: number, category: 'weapon' | 'armor' | 'accessory' | 'treasure') => {
        if (!selectedMember) return;
        const newEquipped = { ...selectedMember.equippedItems };
        const newInventory = { ...selectedMember.personalInventory };
        const currentItemId = newEquipped[category];
        if (currentItemId !== null) newInventory.weapons[currentItemId] = (newInventory.weapons[currentItemId] || 0) + 1;
        if (newInventory.weapons[itemId] > 0) {
            newInventory.weapons[itemId]--;
            if (newInventory.weapons[itemId] === 0) delete newInventory.weapons[itemId];
        }
        newEquipped[category] = itemId;
        onUpdateMember(selectedMember.id, { equippedItems: newEquipped, personalInventory: newInventory });
        setFocusedBagItem(null);
    };

    const handleUsePill = (pillId: number, quantity: number) => {
        if (!selectedMember) return;
        const pillData = PILL_DETAILS[pillId] as any;
        if (!pillData) return;
        if (pillData.requiredRealm && selectedMember.realm !== pillData.requiredRealm) {
            setFocusedBagItem(null);
            hideTooltip();
            return;
        }
        const newInventory = { ...selectedMember.personalInventory };
        const currentCount = newInventory.pills[pillId] || 0;
        if (currentCount < quantity) return;
        newInventory.pills[pillId] -= quantity;
        if (newInventory.pills[pillId] === 0) delete newInventory.pills[pillId];
        const updates: Partial<ClanMember> = { personalInventory: newInventory };
        const pillEffects = pillData.effects;
        if (pillEffects) {
            if (pillEffects.cultivationProgress) updates.cultivationProgress = (selectedMember.cultivationProgress || 0) + (pillEffects.cultivationProgress * quantity);
            if (pillEffects.status) updates.status = pillEffects.status;
            if (pillEffects.maxAge) updates.maxAge = (selectedMember.maxAge || 0) + (pillEffects.maxAge * quantity);
            if (pillEffects.divineSense) updates.divineSense = (selectedMember.divineSense || 0) + (pillEffects.divineSense * quantity);
        }
        onUpdateMember(selectedMember.id, updates);
        setFocusedBagItem(null); setUseQuantity(1); hideTooltip();
    };

    const renderNamePlaque = (member: ClanMember) => (
        <div className={`border-2 border-black bg-red-950/60 px-6 py-2 shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-sm ${member.tier === '绝世天骄' ? 'ring-1 ring-red-500/50' : ''}`}>
            <h2 className="text-xl sm:text-2xl lg:text-3xl font-cursive tracking-wider text-center whitespace-nowrap">
                <span className="text-yellow-400">{member.name}</span>
                {member.title && <><span className="mx-1 text-black font-bold">·</span><span className={`${getTitleColor(member.tier)}`}>{member.title}</span></>}
            </h2>
        </div>
    );

    const renderSlotItem = (methodId: number | null, type: MethodType, label: string, slotKey: string) => {
        const method = CULTIVATION_METHODS.find(m => m.id === methodId);
        const isFocused = focusedSlot === slotKey;
        const style = method ? getGradeStyle(method.grade) : null;
        return (
            <div className="flex flex-col items-center gap-1 group relative">
                <div onClick={() => methodId !== null && setFocusedSlot(isFocused ? null : slotKey)}
                    onMouseEnter={(e) => method && showTooltip(e, renderMethodTooltipContent(method))}
                    onMouseLeave={hideTooltip}
                    className={`relative cursor-pointer transition-all duration-300 rounded-md border-2 flex items-center justify-center w-12 h-12 sm:w-14 sm:h-14 ${isFocused ? 'border-yellow-500 shadow-[0_0_10px_rgba(234,179,8,0.5)]' : (style ? style.border : 'border-yellow-900/20')} ${style ? style.bg : 'bg-black/40'} overflow-hidden`}>
                    {method ? <div className={`w-full h-full p-1 flex flex-col items-center justify-center text-center font-bold ${style?.text}`}>📜<span className="text-[7px] sm:text-[8px] leading-tight line-clamp-2 mt-0.5">{method.name}</span></div> : <div className="text-gray-800 text-[8px] sm:text-[9px] opacity-20 italic font-bold">{label}</div>}
                    {methodId !== null && isFocused && (
                        <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center p-0.5 animate-fade-in z-20">
                            <button onClick={(e) => { e.stopPropagation(); if (methodId !== null) toggleMethod(methodId, type); hideTooltip(); }} className="bg-red-900/80 hover:bg-red-700 text-white text-[7px] py-0.5 px-1 rounded-full border border-red-500/50">卸下</button>
                        </div>
                    )}
                </div>
                <div className="bg-black/60 px-1 py-0.5 rounded-full border border-yellow-900/40 shadow-sm"><span className="text-[7px] sm:text-[8px] text-yellow-500/80 font-bold whitespace-nowrap">{label}</span></div>
            </div>
        );
    };

    const renderEquipSlot = (itemId: number | null, label: string, icon: string, slotKey: keyof ClanMember['equippedItems']) => {
        const isFocused = focusedEquipSlot === slotKey;
        const itemDetails = itemId !== null ? ALL_ITEM_DETAILS[itemId] : null;
        const style = itemDetails ? getGradeStyle(itemDetails.grade) : null;
        return (
            <div className="flex flex-col items-center gap-1 relative">
                <div onClick={() => itemId !== null && setFocusedEquipSlot(isFocused ? null : slotKey)}
                    onMouseEnter={(e) => itemId !== null && showTooltip(e, renderItemTooltipContent(itemId))}
                    onMouseLeave={hideTooltip}
                    className={`w-12 h-12 sm:w-16 sm:h-16 rounded border-2 flex items-center justify-center transition-all cursor-pointer relative overflow-hidden ${itemDetails ? `${style?.border} ${style?.text} ${style?.bg}` : 'bg-black/40 border-white/10 text-gray-800'}`}>
                    <span className="font-bold text-[10px] px-1 text-center leading-tight">{itemDetails ? itemDetails.name : icon}</span>
                </div>
                {itemId !== null && isFocused && <button onClick={(e) => { e.stopPropagation(); handleUnequip(slotKey); hideTooltip(); }} className={`absolute top-1/2 -translate-y-1/2 z-30 bg-red-800 text-white text-[10px] py-1 px-2 rounded-sm font-bold shadow-lg border border-red-500 ${slotKey === 'weapon' || slotKey === 'armor' ? '-right-10' : '-left-10'}`}>卸下</button>}
                <span className="text-[10px] text-gray-600 mt-1">{label}</span>
            </div>
        );
    };

    const renderBagItem = (icon: string, id: number, count: number, onAction?: (qty: number) => void, actionLabel?: string) => {
        const details = ALL_ITEM_DETAILS[id] as any;
        if (!details) return null;
        const style = getGradeStyle(details.grade);
        const isRestricted = details.requiredRealm && selectedMember?.realm !== details.requiredRealm;
        return (
            <div key={id} onClick={() => setFocusedBagItem(focusedBagItem === id ? null : id)}
                onMouseEnter={(e) => showTooltip(e, renderItemTooltipContent(id))}
                onMouseLeave={hideTooltip}
                className={`${style.bg} border-2 ${style.border} p-3 rounded-lg flex flex-col items-center transition-all aspect-[4/5] justify-between shadow-lg relative overflow-hidden ${isRestricted ? 'opacity-50 grayscale' : ''}`}>
                <div className="text-3xl mt-2">{icon}</div>
                <span className={`text-[12px] font-bold text-center truncate w-full mt-2 px-1 ${style.text}`}>{details.name}</span>
                <span className="text-[11px] font-bold text-yellow-600/80 mt-auto font-mono">数量：{count}</span>
                {onAction && focusedBagItem === id && (
                    <div className="absolute inset-0 bg-black/90 flex flex-col items-center justify-center z-10 p-2">
                        {isRestricted ? <div className="text-red-500 text-[10px] font-bold">境界不足</div> : 
                        <button onClick={(e) => { e.stopPropagation(); onAction(useQuantity); hideTooltip(); }} className="text-white text-[11px] py-1.5 px-3 rounded font-bold w-full bg-yellow-800">服用/佩戴</button>}
                        <button onClick={(e) => { e.stopPropagation(); setFocusedBagItem(null); }} className="mt-1 text-[9px] text-gray-500">取消</button>
                    </div>
                )}
            </div>
        );
    };

    const sortedBagItems = useMemo(() => {
        if (!selectedMember) return [];
        const inv = selectedMember.personalInventory;
        const itemsList: Array<{ id: number; count: number; category: BagSubTab }> = [];
        const addItems = (record: Record<number, number>, category: BagSubTab) => Object.entries(record).forEach(([id, count]) => { if (count > 0) itemsList.push({ id: parseInt(id), count, category }); });
        if (bagSubTab === 'all' || bagSubTab === 'equipment') addItems(inv.weapons, 'equipment');
        if (bagSubTab === 'all' || bagSubTab === 'pills') addItems(inv.pills, 'pills');
        if (bagSubTab === 'all' || bagSubTab === 'materials') { addItems(inv.herbs, 'materials'); addItems(inv.minerals, 'materials'); }
        if (bagSubTab === 'all' || bagSubTab === 'methods') addItems(inv.methods, 'methods');

        // Fix: Correctly handle string (e.g., '神器残片') or number grades for arithmetic sorting
        return itemsList.sort((a, b) => {
            const gradeB = ALL_ITEM_DETAILS[b.id]?.grade;
            const gradeA = ALL_ITEM_DETAILS[a.id]?.grade;
            const valB = typeof gradeB === 'number' ? gradeB : (gradeB === '神器残片' ? 9 : 0);
            const valA = typeof gradeA === 'number' ? gradeA : (gradeA === '神器残片' ? 9 : 0);
            return valB - valA;
        });
    }, [selectedMember, bagSubTab]);

    const renderStatusTab = () => {
        if (!selectedMember) return null;
        const statusInfo = TASK_INFO[selectedMember.assignment];
        const multiplier = selectedMember.assignment === 'Cultivation' ? '100%' :
                          selectedMember.assignment === 'Idle' ? '20%' :
                          (selectedMember.assignment === 'Alchemy' || selectedMember.assignment === 'Smithing' || selectedMember.assignment === 'Research') ? '60%' :
                          selectedMember.assignment === 'Mission' ? '40%' :
                          selectedMember.assignment === 'Travel' ? '10%' : '0%';

        return (
            <div className="h-full flex flex-col animate-fade-in p-4 space-y-6">
                <div className="bg-black/30 border-2 border-yellow-900/20 p-6 rounded-xl text-center">
                    <h4 className="text-gray-500 text-xs uppercase tracking-widest mb-2">当前人物状态</h4>
                    <p className={`text-4xl font-cursive ${statusInfo.color} mb-4`}>{statusInfo.label}</p>
                    <div className="h-px bg-yellow-900/10 w-24 mx-auto mb-4"></div>
                    <p className="text-sm text-gray-400 italic leading-relaxed px-4">{statusInfo.desc}</p>
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div className="bg-black/40 p-4 rounded-lg border border-white/5">
                        <p className="text-[10px] text-gray-500 mb-1">修行效率</p>
                        <p className="text-2xl font-mono text-yellow-500 font-bold">{multiplier}</p>
                    </div>
                    <div className="bg-black/40 p-4 rounded-lg border border-white/5">
                        <p className="text-[10px] text-gray-500 mb-1">因果牵引</p>
                        <p className="text-2xl font-mono text-blue-500 font-bold">1.0x</p>
                    </div>
                </div>

                <div className="flex-1 border-t border-yellow-900/10 pt-4">
                    <h5 className="text-xs text-yellow-600 font-bold mb-4">状态自动流转说明</h5>
                    <ul className="text-[11px] text-gray-500 space-y-2 list-disc pl-4">
                        <li><span className="text-blue-400">闭关修炼</span>：默认修行状态。</li>
                        <li><span className="text-emerald-400">休养生息</span>：重伤后自动切换，无法手动更改。</li>
                        <li><span className="text-pink-400">炼丹/炼器/研习</span>：担任对应家族职司后开启。</li>
                        <li><span className="text-orange-400">外出派遣</span>：执行领地任务期间生效。</li>
                        <li><span className="text-yellow-500">外出游历</span>：突发事件触发，可能获得奇遇。</li>
                    </ul>
                </div>
            </div>
        );
    };

    return (
        <div className="bg-[#1e130c] border-l-4 border-yellow-800 h-full flex flex-col relative overflow-hidden font-serif">
            {tooltip && tooltip.visible && <div className="fixed z-[10000] pointer-events-none bg-black/95 border-2 border-yellow-900/50 p-4 rounded shadow-2xl animate-fade-in" style={{ left: tooltip.x, top: tooltip.y, transform: `translate(-50%, ${tooltip.y > window.innerHeight / 2 ? '-100%' : '0'})` }}>{tooltip.content}</div>}
            <div className="p-4 border-b border-yellow-900/30 bg-black/40 shrink-0">
                <h2 className="text-xl font-cursive text-yellow-500 mb-4">⛩️ 族谱常青</h2>
                <div className="flex p-1 bg-black/40 rounded-lg gap-1 border border-yellow-900/10">
                    <button onClick={() => handleTabChange('alive')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'alive' ? 'bg-yellow-800 text-yellow-100' : 'text-gray-500'}`}>在世族人</button>
                    <button onClick={() => handleTabChange('deceased')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'deceased' ? 'bg-gray-800 text-gray-100' : 'text-gray-500'}`}>英灵祠堂</button>
                </div>
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar">
                {pagedMembers.map(m => (
                    <div key={m.id} onClick={() => activeTab === 'alive' && setSelectedMemberId(m.id)} className={`p-3 rounded-md border transition-all cursor-pointer ${selectedMemberId === m.id ? 'bg-[#2d1e15] border-yellow-600' : 'bg-[#1e130c] border-yellow-900/30'}`}>
                        <div className="flex justify-between items-start">
                            <span className="font-bold text-sm text-yellow-100">{m.name}</span>
                            <span className={`text-[10px] ${TASK_INFO[m.assignment].color}`}>{TASK_INFO[m.assignment].label}</span>
                        </div>
                        <div className="flex justify-between text-[10px] mt-2">
                            <span className={getRealmStyle(m.realm).split(' ')[2]}>{getRealmText(m.realm, m.subRealm)}</span>
                            <span className={getTierColor(m.tier)}>{m.tier}</span>
                        </div>
                    </div>
                ))}
            </div>
            {selectedMember && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 p-4 overflow-hidden">
                    <div className="relative w-full max-w-6xl h-full bg-[#1a2521] border-[12px] border-[#2c3e34] rounded-sm flex flex-col">
                        <div className="h-16 bg-[#141e1b] border-b border-[#2c3e34] flex items-center px-8 shrink-0">
                            <div className="flex gap-4 h-full">
                                {['attr', 'status', 'talents', 'relations', 'cultivation', 'bag', 'plan'].map(t => (
                                    <button key={t} onClick={() => setDetailTab(t as any)} className={`px-4 h-full text-xs font-bold border-b-4 ${detailTab === t ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500'}`}>
                                        {t === 'attr' ? '👤 属性' : t === 'status' ? '✨ 状态' : t === 'talents' ? '📜 天赋' : t === 'relations' ? '🤝 关系' : t === 'cultivation' ? '🌀 功法' : t === 'bag' ? '🎒 行囊' : '🗺️ 计划'}
                                    </button>
                                ))}
                            </div>
                            <button onClick={() => setSelectedMemberId(null)} className="ml-auto w-9 h-9 bg-red-900/20 text-red-500 rounded-full flex items-center justify-center text-xl font-bold">×</button>
                        </div>
                        <div className="flex-1 flex overflow-hidden">
                            <div className="w-[35%] border-r border-[#2c3e34] p-8 bg-black/10 flex flex-col items-center">
                                {renderNamePlaque(selectedMember)}
                                <div className="relative flex items-center justify-center gap-6 py-8">
                                    <div className="flex flex-col gap-8">{renderEquipSlot(selectedMember.equippedItems.weapon, '武器', '⚔️', 'weapon')}{renderEquipSlot(selectedMember.equippedItems.armor, '防具', '🛡️', 'armor')}</div>
                                    <div className="w-44 h-64 bg-black/40 rounded-full border-2 border-yellow-900/20 flex items-center justify-center text-7xl opacity-10">🧘</div>
                                    <div className="flex flex-col gap-8">{renderEquipSlot(selectedMember.equippedItems.accessory, '饰品', '💍', 'accessory')}{renderEquipSlot(selectedMember.equippedItems.treasure, '法宝', '🔮', 'treasure')}</div>
                                </div>
                                <div className="w-full mt-4 p-4 bg-black/30 border border-yellow-900/10 rounded">
                                    <div className="flex justify-between items-center mb-2"><span className="text-[10px] text-gray-500 font-bold">修为进度</span></div>
                                    <div className="w-full h-2 bg-gray-900 rounded-full overflow-hidden border border-white/10"><div className="h-full bg-blue-600" style={{ width: `${(selectedMember.cultivationProgress / getRequiredExp(REALM_ORDER.indexOf(selectedMember.realm), selectedMember.subRealm)) * 100}%` }}></div></div>
                                </div>
                            </div>
                            <div className="flex-1 p-8 overflow-y-auto custom-scrollbar bg-[#1a2521]/50">
                                {detailTab === 'status' ? renderStatusTab() : detailTab === 'bag' ? <div className="grid grid-cols-4 gap-4">{sortedBagItems.map(item => renderBagItem('📦', item.id, item.count))}</div> : <p className="text-gray-500 italic text-center py-20">此处暂未开放详细内容...</p>}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ClanDashboard;
